SELECT ?film ?filmLabel WHERE {
  ?film wdt:P407 wd:Q1860 ;
        wdt:P3382 ?person ;
        rdfs:label ?filmLabel .
  ?person rdfs:label ?personLabel .
  FILTER (CONTAINS(LCASE(?personLabel), "laxman utekar") && LANG(?personLabel) = "en" && LANG(?filmLabel) = "en")
  ?film wdt:P577 ?date .
}
ORDER BY ?date
LIMIT 1

